def open_file(filepath = None):
    #global filePathStr
    global photoFile
    #global imageViewer
    global img
    global enh
    global imageViewer_width
    global imageViewer_height
    global imageViewer_top
    global imageViewer_left
    global lastFile
    global filesarray

    if filepath is None:
        filepath = askopenfilename(filetypes=[("Image Files", "*.jpg *.jpeg *.bmp *.png"), ("All Files", "*.*")])
    if not filepath: return None
    print(f"Open from:{filepath}")
    resetValues()
    filePathStr.set(filepath)
    img = Image.open(filepath)
    
    if filepath in filesarray:
      pass
    else:
      filelist.insert("end", os.path.basename(filepath).split('/')[-1])
      filesarray.append(filepath)

    print (filesarray)
    lastFile = filepath
    enh = img
    sizeLbl.config(text=f"Size: {img.width} x {img.height} pixel")
    if img.width > imageViewer_width:
        p = img.width / imageViewer_width
        new_w = int(img.width/p)
        new_h = int(img.height/p)
        enh = img.resize([new_w, new_h])
    if enh.height > imageViewer_height:
        p = enh.height / imageViewer_height
        new_w = int(enh.width/p)
        new_h = int(enh.height/p)
        enh = enh.resize([new_w, new_h])
    
    imageViewer_top = int((imageViewer_height/2) - (enh.height/2))
    imageViewer_left = int((imageViewer_width/2) - (enh.width/2))
    tlLbl.config(text=f"Top: {imageViewer_top} - Left: {imageViewer_left}")
    
    photoFile = ImageTk.PhotoImage(enh)
    imageViewer.create_image(imageViewer_left, imageViewer_top, image=photoFile, anchor="nw")
    #imageViewer.create_image(0, 0, image=photoFile, anchor="nw")
    return True

def save_file(filepath = None):
  global img
  global enh
  global coordinateImg
  global setSizeFlag
  global ifChange

  pic = img

  if setSizeFlag: pic = sizeChange(pic, (1654, 2339, 200))

  if filepath is None: filepath = filePathStr.get()
  print(f"Save to:{filepath}")
  pic = enhanced(pic)
  srcPoints = []
  xT = 1.0
  yT = 1.0
  if enh.width != pic.width or enh.height != pic.height:
    xT = enh.width / pic.width
    yT = enh.height / pic.height
  
  if len(coordinateImg) > 0:
    for c in coordinateImg:
      xx = c[1]
      yy = c[2]
      
      if xT<1.0: xx /= xT
      else: xx *= xT
    
      if yT<1.0: yy /= yT
      else: yy *= yT
    
      srcPoints.append((xx, yy))
    pic = transformed(pic, srcPoints)

  pic.save(filepath)
  ifChange = False

def save_as_file():
  filename = filePathStr.get().split('\\')[-1]
  filename = filename.split('/')[-1]
  f = asksaveasfile(initialfile = filename,
    defaultextension=".jpg",filetypes=[("JPEG File","*.jpg"),("PNG File","*.png"),("BMP File","*.bmp"),("All Files","*.*")])
  if f:
    save_file(f.name)

def getTempfile():
   global lastFile
   tmp = tempfile.TemporaryDirectory()
   tmp = tmp.name.split('\\')[:-1]
   tmp = '\\'.join(tmp)
   fn, ext = os.path.splitext(lastFile)
   fil = tmp + "\mpic" + ext
   return fil

def print_file():
  fil = getTempfile()
  f = open(fil, "w")
  #print(fil)
  save_file(fil)
  win32api.ShellExecute(0, "print", fil, None, ".", 0)
  f.close()

def sizeChange(src, size=(1653, 2338, 200)):
  fil = getTempfile()
  src = src.resize((size[0], size[1]))
  src.save(fil, dpi=(size[2],size[2]))
  return Image.open(fil)

def enhanced(src, bright = None, contrast = None, sharp = None, color=None):
  global brightnessVal
  global contrastVal
  global sharpnessVal
  global colorVal
  
  if bright is not None: brightnessVal = bright
  if contrast is not None: contrastVal = contrast
  if sharp is not None: sharpnessVal = sharp
  if color is not None: colorVal = color
  
  #print(f"{brightnessVal}, {contrastVal}, {sharpnessVal}, {colorVal}")

  #if sharpnessVal == 0: sharpnessVal = 1
  if brightnessVal == 0: brightnessVal = 0.1
  if contrastVal == 0: contrastVal = 1
  
  pic = ImageEnhance.Brightness(src)
  pic = pic.enhance(brightnessVal)
    
  pic = ImageEnhance.Contrast(pic)
  pic = pic.enhance(contrastVal)
    
  pic = ImageEnhance.Sharpness(pic)
  pic = pic.enhance(sharpnessVal)

  pic = ImageEnhance.Color(pic)
  pic = pic.enhance(colorVal)

  brightnessScale.set((brightnessVal - 1.0) * 100.0)
  contrastScale.set((contrastVal - 1.0) * 100.0)
  sharpnessScale.set(sharpnessVal * 10.0)
  colorScale.set((colorVal - 1.0) * 10.0)

  return pic

def applyChanges(bright=None, contrast=None, sharp=None, color=None):
  global enh
  global photoFile
  global ifChange
  global imageViewer_left
  global imageViewer_top

  pic = enhanced(enh, bright, contrast, sharp, color)
    
  photoFile = ImageTk.PhotoImage(pic)
  #imageViewer.create_image(0,0,image=photoFile, anchor="nw")
  imageViewer.create_image(imageViewer_left, imageViewer_top, image=photoFile, anchor="nw")
  ifChange = True

def brightnessChange(val):
    global brightnessVal
    
    time.sleep(0.1)
    val = int(val)
    #if val<0: val /= 10.0
    val /=100.0
    val += 1.0
    #if val>=0: val += 1.0
    brightnessVal = val
    
    applyChanges()

def sharpnessChange(val):
    global sharpnessVal
    
    time.sleep(0.1)
    val = int(val)/10.0
    sharpnessVal = val
    
    applyChanges()

def contrastChange(val):
    global contrastVal
    
    time.sleep(0.1)
    val = int(val)
    #if val<0: val /= 10.0
    val /=100.0
    val += 1.0
    contrastVal = val
    
    applyChanges()

def colorChange(val):
    global colorVal
    
    time.sleep(0.1)
    val = int(val)
    #if val<0: val /= 10.0
    val /=10.0
    val += 1.0
    colorVal = val
    #print(colorVal)
    applyChanges()

def transformed(src, srcPoints):
  global imageViewer_left
  global imageViewer_top
  
  def find_data(source, target):
    matrix = []
    for s, t in zip(source, target):
      matrix.append([t[0], t[1], 1, 0, 0, 0, -s[0]*t[0], -s[0]*t[1]])
      matrix.append([0, 0, 0, t[0], t[1], 1, -s[1]*t[0], -s[1]*t[1]])
    A = numpy.matrix(matrix, dtype=float)
    B = numpy.array(source).reshape(8)
    res = numpy.dot(numpy.linalg.inv(A.T * A) * A.T, B)
    return numpy.array(res).reshape(8)
  
  #trgPoints = [(imageViewer_left, imageViewer_top), ((src.width+imageViewer_left), imageViewer_top), ((src.width+imageViewer_left), (src.height+imageViewer_top)), (imageViewer_left, (src.height+imageViewer_top))]
  trgPoints = [(0, 0), (src.width, 0), (src.width, src.height), (0, src.height)]
  coeffs = find_data(srcPoints, trgPoints)

  pic = src.transform(src.size, Image.PERSPECTIVE, coeffs, resample=Image.BICUBIC, fillcolor=(255,255,255))
  return pic

def perspectiveCrop():
  global enh
  global photoFile
  global coordinateVal
  global coordinateImg
  global imageViewer_left
  global imageViewer_top
  global polygonDrawed
  
  srcPoints = []
  for c in coordinateVal: srcPoints.append((c[1],c[2]))
  enh = transformed(enh, srcPoints)
  photoFile = ImageTk.PhotoImage(enh)
  #imageViewer.create_image(0,0,image=photoFile, anchor="nw")
  imageViewer.create_image(imageViewer_left, imageViewer_top,image=photoFile, anchor="nw")
  
  for c in coordinateVal: imageViewer.delete(c[0])
  imageViewer.delete("polygon")
  coordinateImg = coordinateVal
  coordinateVal = []
  polygonDrawed = False
  applyChanges()

def drawPolygon():
  points = []
  imageViewer.delete("polygon")
  for c in coordinateVal:
    points.append(c[1] + imageViewer_left)
    points.append(c[2] + imageViewer_top)
  imageViewer.create_polygon(points, outline="red", fill="white", stipple="gray50", width=3, tags="polygon")

