def mouse_ldbclick(event):
  global enh
  global polygonDrawed
  global imageViewer_left
  global imageViewer_top
  global circleRadius

  xloc = event.x
  yloc = event.y
  if len(coordinateVal)<4:
    coordinateVal.append([f"Point_{len(coordinateVal)}", xloc - imageViewer_left, yloc - imageViewer_top])
    oval = imageViewer.create_oval(xloc-circleRadius, yloc-circleRadius, xloc+circleRadius, yloc+circleRadius, 
                   fill="lightblue", 
                   outline="blue", 
                   width=2,
                   tags=coordinateVal[-1][0])
    MakeDraggable(imageViewer, oval)
  if len(coordinateVal)==4:
    drawPolygon()
    polygonDrawed = True
    print(coordinateVal)

def mouse_rdbclick(event):
  global polygonDrawed
  if len(coordinateVal)>0:
    imageViewer.delete(coordinateVal[-1][0])
    coordinateVal.pop()
    if len(coordinateVal)==3:
      imageViewer.delete("polygon")
      polygonDrawed = False
  print(coordinateVal)

def mouse_popup(event):
  try:
    contaxtMenu.tk_popup(event.x_root, event.y_root)
  finally:
    contaxtMenu.grab_release()

def key_released(event):
  if event.keysym=='Return' and polygonDrawed == True:
    perspectiveCrop()
  elif event.keysym=='w' or event.keysym=='W':
    save_file()

def MakeDraggable(can, widget):
  can.tag_bind(widget, "<Button-1>", OnDragStart)
  can.tag_bind(widget, "<B1-Motion>", OnDragMotion)

def OnDragStart(event):
  global objToMove
  objToMove = imageViewer.find_closest(event.x, event.y)
  
  #widget = event.widget
  #widget._drag_start_x = event.x
  #widget._drag_start_y = event.y

def OnDragMotion(event):
  global objToMove
  global circleRadius
  global polygonDrawed
  global coordinateVal

  if objToMove:
    obj = imageViewer.gettags(objToMove)[0]
    tag = obj.split("_")
    if tag[0]=="Point":
      xPos = event.x
      yPos = event.y
      xObject = imageViewer.coords(objToMove)[0]+circleRadius
      yObject = imageViewer.coords(objToMove)[1]+circleRadius
    
      imageViewer.move(obj, xPos-xObject, yPos-yObject)
      coordinateVal[int(tag[1])][1] += (xPos-xObject)
      coordinateVal[int(tag[1])][2] += (yPos-yObject)
      if polygonDrawed:
        imageViewer.delete("polygon")
        drawPolygon()
    
  #widget = event.widget
  #x = widget.winfo_x() - widget._drag_start_x + event.x
  #y = widget.winfo_y() - widget._drag_start_y + event.y
  #widget.place(x = x, y = y)

def setSize(sz='A4'):
  global enh
  global photoFile
  global setSizeFlag

  pic = None
  if sz=='A4':
    pic = sizeChange(enh, (1654, 2339, 200))
  elif sz=='A5':
    pic = sizeChange(enh, (1170, 1654, 200))
  
  if pic.width>int(mainForm_W*0.7):
    p = pic.width/(mainForm_W*0.7)
    new_w = int(pic.width/p)
    new_h = int(pic.height/p)
    enh = pic.resize([new_w, new_h])
  if pic.height>int(mainForm_H-40):
    p = pic.height/(mainForm_H-40)
    new_w = int(pic.width/p)
    new_h = int(pic.height/p)
    enh = pic.resize([new_w, new_h])

  photoFile = ImageTk.PhotoImage(enh)
  #imageViewer.create_image(0,0,image=photoFile, anchor="nw")
  imageViewer.create_image(((imageViewer_width/2) - (enh.width/2)),0,image=photoFile, anchor="nw")
  setSizeFlag = True

